--KDA= a*(1-1/(击杀*b+拆床*c+助攻*d+e))/(死亡*f+g)+h
function PlayerInfo:getKDA()
    local param = { 18, 0.3, 1.2, 0.21, 1.2, 0.1, 1, 1 }
    local kill = tonumber(self:getValue("kill"))
    local die = tonumber(self:getValue("die"))
    local assist = tonumber(self:getValue("assist"))
    local bed = #self:getValue("destroy_bed")
    local kda = param[1] * (1 - 1 / (kill * param[2] + bed * param[3] + assist * param[4] + param[5])) / (die * param[6] + param[7]) + param[8]
    kda = math.floor(kda * 10) / 10
    if tonumber(self:getValue("isMvp")) == 1 then
        kda = kda + 0.1
    end
    return kda
end

function PlayerInfo:addCup(cupId)
    local cupIds = self:getCupIds()
    table.insert(cupIds, tostring(cupId))
    self:setValue("cups", table.concat(cupIds, "#"))
end

function PlayerInfo:getCupIds()
    local cupsStr = self:getValue("cups")
    local cupIds = StringUtil.split(cupsStr, "#")
    return cupIds
end

return PlayerInfo